import React, { useState, useEffect } from 'react';
import { useParams, Link } from 'react-router-dom';
import HighlightMenu from '../components/HighlightMenu';
import FeedbackSection from '../components/FeedbackSection';
import Button from '../components/Button';

const ArticlePage = () => {
    const { id } = useParams();
    const [highlightPosition, setHighlightPosition] = useState(null);
    const [selectedText, setSelectedText] = useState('');
    const [showHighlightMenu, setShowHighlightMenu] = useState(false);
    const [aiResponse, setAiResponse] = useState(null);

    // Mock Article Data (In a real app, fetch based on ID)
    const article = {
        title: "The Future of AI is Personal",
        author: "Sarah Jenkins",
        date: "Nov 24, 2025",
        source: "TechDaily",
        imageUrl: "https://images.unsplash.com/photo-1677442136019-21780ecad995?auto=format&fit=crop&q=80&w=1200",
        content: `
      Artificial Intelligence is no longer just a buzzword; it's becoming a deeply personal part of our daily lives. From personalized learning algorithms to health monitoring systems that know your body better than you do, the next wave of AI is all about context.

      But with this power comes a significant responsibility. How do we ensure that these systems remain tools for empowerment rather than instruments of control? The answer lies in transparency and user agency. We need to build systems that explain their reasoning, allowing users to understand not just the 'what', but the 'why'.

      Furthermore, the economic implications are vast. As automation takes over routine tasks, the value of human creativity and emotional intelligence will skyrocket. We are entering an era where the most valuable skill will be the ability to ask the right questions, rather than just knowing the right answers.
    `
    };

    useEffect(() => {
        const handleSelection = () => {
            const selection = window.getSelection();
            const text = selection.toString().trim();

            if (text.length > 0) {
                const range = selection.getRangeAt(0);
                const rect = range.getBoundingClientRect();

                setSelectedText(text);
                setHighlightPosition({
                    top: rect.top,
                    left: rect.left,
                    width: rect.width,
                    height: rect.height
                });
                setShowHighlightMenu(true);
            } else {
                // Only hide if we aren't interacting with the menu
                // This is a simplified check; in production, use a ref to check click target
                // setShowHighlightMenu(false);
            }
        };

        document.addEventListener('mouseup', handleSelection);
        return () => document.removeEventListener('mouseup', handleSelection);
    }, []);

    const handleAiAction = (action, query) => {
        console.log(`AI Action: ${action}, Query: ${query}, Text: ${selectedText}`);

        // Mock AI Response
        let responseText = "";
        if (action === 'simplify') {
            responseText = "In simpler terms: AI is getting to know us better to help us more, but we need to make sure we stay in charge.";
        } else if (action === 'explain') {
            responseText = "This section discusses the ethical balance between helpful AI and controlling AI, emphasizing the need for systems that can explain their decisions.";
        } else if (action === 'custom') {
            responseText = `AI says: That's a great question about "${selectedText}". Here is a tailored explanation...`;
        }

        setAiResponse(responseText);
        setShowHighlightMenu(false);
        window.getSelection().removeAllRanges();
    };

    return (
        <div className="min-h-screen bg-cream-50 pb-20">
            {/* Hero Image */}
            <div className="h-[40vh] w-full relative border-b-4 border-black">
                <img src={article.imageUrl} alt={article.title} className="w-full h-full object-cover" />
                <div className="absolute inset-0 bg-black/20"></div>
                <Link to="/headlines" className="absolute top-6 left-6">
                    <Button variant="secondary" className="text-sm">← BACK</Button>
                </Link>
            </div>

            <div className="max-w-3xl mx-auto px-6 -mt-20 relative z-10">
                {/* Header Card */}
                <div className="bg-white border-4 border-black p-8 shadow-hard mb-12">
                    <div className="flex items-center gap-4 mb-4 text-sm font-bold text-gray-500 uppercase tracking-wider">
                        <span className="text-soft-blue-600">{article.source}</span>
                        <span>•</span>
                        <span>{article.date}</span>
                    </div>
                    <h1 className="font-serif text-4xl md:text-5xl font-black mb-6 leading-tight">
                        {article.title}
                    </h1>
                    <div className="flex items-center gap-3">
                        <div className="w-10 h-10 bg-gray-200 rounded-full border-2 border-black"></div>
                        <p className="font-bold">By {article.author}</p>
                    </div>
                </div>

                {/* AI Response Card (Dynamic) */}
                {aiResponse && (
                    <div className="bg-soft-blue-100 border-4 border-black p-6 mb-8 animate-fade-in relative">
                        <button
                            onClick={() => setAiResponse(null)}
                            className="absolute top-2 right-2 font-bold text-gray-500 hover:text-black"
                        >
                            ✕
                        </button>
                        <p className="font-bold text-soft-blue-800 text-sm uppercase mb-2">AI Insight</p>
                        <p className="font-serif text-xl leading-relaxed">{aiResponse}</p>
                    </div>
                )}

                {/* Article Content */}
                <div className="prose prose-lg max-w-none font-serif text-gray-800 leading-loose mb-16">
                    {article.content.split('\n').map((paragraph, idx) => (
                        paragraph.trim() && <p key={idx} className="mb-6 text-xl">{paragraph.trim()}</p>
                    ))}
                </div>

                {/* Feedback Section */}
                <FeedbackSection />
            </div>

            {/* Floating Highlight Menu */}
            {showHighlightMenu && (
                <HighlightMenu
                    position={highlightPosition}
                    onAction={handleAiAction}
                    onClose={() => {
                        setShowHighlightMenu(false);
                        window.getSelection().removeAllRanges();
                    }}
                />
            )}
        </div>
    );
};

export default ArticlePage;
